text:
function: () => ({
  processButtons: document.querySelectorAll('.scanner-process').length,
  resultBoxes: document.querySelectorAll('.scanner-result').length,
  freezerBtnText: document.querySelector('#scanners-freezer .scanner-process')?.textContent,
  freezerBtnDisabled: document.querySelector('#scanners-freezer .scanner-process')?.disabled,
})

function: async () => {
  const btn = document.querySelector('#scanners-freezer .scanner-process');
  btn.disabled = false;
  btn.click();
  // wait for the controller's POST + view.render to complete
  const box = document.querySelector('#scanners-freezer .scanner-result');
  const start = Date.now();
  while (Date.now() - start < 60000) {
    if (box.innerHTML.includes('pipeline-stages') || box.innerHTML.includes('pipeline-error')) break;
    await new Promise(r => setTimeout(r, 300));
  }
  return {
    hidden: box.classList.contains('hidden'),
    stageNames: [...box.querySelectorAll('.pipeline-stage-name')].map(e => e.textContent),
    statuses: [...box.querySelectorAll('.pipeline-stage-status')].map(e => e.textContent),
    note: box.querySelector('.pipeline-note')?.textContent,
  };
}
